import axios from 'axios';

const signup = async ({username, password, email}) => {
    try{
        const request = await axios.post("/auth/signup",
            {username, password, email}
        );
        console.log(request);
        return request.data;
    }catch(err){
        console.log(err);
    }
}

export default signup;
